     8	// 符号表，保存当前作用域的所有声明
     9	struct Ast2Asg::Symtbl : public std::unordered_map<std::string, Decl*>
    10	{
    11	  Ast2Asg& m;
    12	  Symtbl* mPrev;
    13	
    14	  Symtbl(Ast2Asg& m)
    15	    : m(m)
    16	    , mPrev(m.mSymtbl)
    17	  {
    18	    m.mSymtbl = this;
    19	  }
    20	
    21	  ~Symtbl() { m.mSymtbl = mPrev; }
    22	
    23	  Decl* resolve(const std::string& name);
    24	};
