    26	Decl*
    27	Ast2Asg::Symtbl::resolve(const std::string& name)
    28	{
    29	  auto iter = find(name);
    30	  if (iter != end())
    31	    return iter->second;
    32	  ASSERT(mPrev != nullptr); // 标识符未定义
    33	  return mPrev->resolve(name);
    34	}
