   328	Expr*
   329	Ast2Asg::operator()(ast::InitializerContext* ctx)
   330	{
   331	  if (auto p = ctx->assignmentExpression())
   332	    return self(p);
   333	
   334	  auto ret = make<InitListExpr>();
   335	
   336	  if (auto p = ctx->initializerList()) {
   337	    for (auto&& i : p->initializer()) {
   338	      // 将初始化列表展平
   339	      auto expr = self(i);
   340	      if (auto p = expr->dcst<InitListExpr>()) {
   341	        for (auto&& sub : p->list)
   342	          ret->list.push_back(sub);
   343	      } else {
   344	        ret->list.push_back(expr);
   345	      }
   346	    }
   347	  }
   348	
   349	  return ret;
   350	}
